+
+function parseMaxBytes(url: URL, key: string, defaultValue: number, maxValue: number): number {
+  const raw = url.searchParams.get(key);
+  if (!raw) {
+    return defaultValue;
+  }
+
+  const parsed = Number(raw);
+  if (!Number.isFinite(parsed) || parsed <= 0) {
+    return defaultValue;
+  }
