+  } catch (error) {
+    if (isWorkspacePathValidationError(error)) {
+      return jsonResponse({ error: (error as Error).message }, 400);
+    }
+
+    const message = error instanceof Error ? error.message : String(error);
+    return jsonResponse({ error: message }, 500);
+  }
